options.validator:
(async () => {
  const { table_pi } = this.getValues();
  const fieldParts = rule.field.split(".");
  const index = fieldParts[1];

  const availableInvQty = table_pi[index].available_inv_qty;

  if(value > availableInvQty) {
    callback('Invoice quantity cannot exceed available invoice quantity.');
    return;
  } else {
    callback();
  }
})();

