const page_status = this.getValue('page_status');

if (page_status === 'View' || !value) {
    callback();
    return;
}

let organizationId = this.getVarGlobal('deptParentId');
if(organizationId === '0'){
    organizationId = this.getVarSystem('deptIds').split(',')[0];
}

db.collection("purchase_order")
    .where({ purchase_order_no: value, organization_id: organizationId })
    .get()
    .then(response => {
        const matchingPO = response.data || [];

        if (matchingPO.length === 0) {
            callback();
            return;
        }

        if (page_status === 'Edit') {
            const currentPoNo = this.getValue('id');
            const isSamePO = matchingPO.some(purchase_order => purchase_order.id === currentPoNo);
            callback(isSamePO ? undefined : 'Purchase order number already exists.');
        } else {
            callback('Purchase order number already exists.');
        }
    })
    .catch(error => {
        console.error("Error checking purchase order:", error);
        callback("Error validating purchase order number.");
    });

