const data = this.getValues();
let items = [];

const roundPrice = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(4));
};

if (data.table_pi.length > 0) {
  items = data.table_pi;
} else {
  const { PIlineItem } = arguments[0];
  items = PIlineItem;
}
const exchangeRate = data.exchange_rate;
let totalGross = 0;
let totalDiscount = 0;
let totalTax = 0;
let totalAmount = 0;

if (Array.isArray(items)) {
  items.forEach((item, index) => {
    const quantity = Number(item.invoice_qty) || 0;
    const unitPrice = roundPrice(item.order_unit_price) || 0;
    const grossValue = quantity * unitPrice;

    totalGross += roundPrice(grossValue);

    this.setData({
      [`table_pi.${index}.order_gross`]: roundPrice(grossValue),
      [`table_pi.${index}.invoice_amount`]: roundPrice(grossValue),
      invoice_subtotal: roundPrice(totalGross),
    });

    let discount = parseFloat(item.order_discount) || 0;
    let discountUOM = item.discount_uom;
    let discountAmount = 0.0;
    const taxRate = Number(item.tax_percent) || 0;
    const taxInclusive = item.tax_inclusive;

    if (discount > 0) {
      if (!discountUOM) {
        discountUOM = "Amount";
        this.setData({ [`table_pi.${index}.discount_uom`]: "Amount" });
      }
    }

    if (discountUOM) {
      if (discount !== 0) {
        if (discountUOM === "Amount") {
          discountAmount = roundPrice(discount);
        } else if (discountUOM === "%") {
          discountAmount = roundPrice((grossValue * discount) / 100);
        }

        if (discountAmount > grossValue) {
          discount = 0;
          discountAmount = 0;

          this.setData({
            [`table_pi.${index}.order_discount`]: 0,
            [`table_pi.${index}.discount_amount`]: 0,
          });
        } else {
          this.setData({
            [`table_pi.${index}.discount_amount`]: roundPrice(discountAmount),
          });
        }
      }
    } else {
      this.setData({
        [`table_pi.${index}.discount_amount`]: 0,
      });
    }

    const amountAfterDiscount = roundPrice(grossValue - discountAmount);

    let taxAmount = 0;
    let finalAmount = amountAfterDiscount;

    if (taxRate) {
      const taxRateDecimal = taxRate / 100;

      if (taxInclusive === 1) {
        taxAmount = roundPrice(
          amountAfterDiscount - amountAfterDiscount / (1 + taxRateDecimal)
        );
        finalAmount = amountAfterDiscount;
      } else {
        taxAmount = roundPrice(amountAfterDiscount * taxRateDecimal);
        finalAmount = amountAfterDiscount + taxAmount;
      }

      this.setData({
        [`table_pi.${index}.tax_amount`]: taxAmount,
      });
    } else {
      this.setData({
        [`table_pi.${index}.tax_amount`]: 0,
      });
    }

    // Set final amount
    this.setData({
      [`table_pi.${index}.invoice_amount`]: roundPrice(finalAmount),
    });

    // Subtract previous values before adding new ones
    totalDiscount += roundPrice(discountAmount);
    totalTax += roundPrice(taxAmount);
    totalAmount += roundPrice(finalAmount);

    if (totalTax > 0) {
      this.display(["invoice_taxes_amount", "total_tax_currency"]);
    }

    this.setData({
      invoice_total_discount: roundPrice(totalDiscount),
      invoice_taxes_amount: roundPrice(totalTax),
      invoice_total: roundPrice(totalAmount),
    });

    if (!exchangeRate) {
      return;
    } else {
      const myrTotalAmount = (exchangeRate || 1) * totalAmount;
      this.setData({ myr_total_amount: roundPrice(myrTotalAmount) });
    }
  });
} else {
  console.log("Not an array:", items);
}

