          goods_receiving_no: grItem.goods_receiving_number,
          line_remark_1: grItem.line_remark_1 || "",
          line_remark_2: grItem.line_remark_2 || "",
          invoice_qty: grItem.received_qty - (grItem.invoiced_qty || 0),
          quantity_uom: grItem.uom,
          order_unit_price: grItem.po_line_item.unit_price,
          order_discount: grItem.po_line_item.discount,
          discount_uom: grItem.po_line_item.discount_uom,
          tax_percent: grItem.po_line_item.tax_percent,
          tax_preference: grItem.po_line_item.tax_preference,
          tax_inclusive: grItem.po_line_item.tax_inclusive,
          gr_line_id: grItem.goods_receiving_line_id,
          po_line_id: grItem.po_line_item.id,
          available_inv_qty: grItem.received_qty - (grItem.invoiced_qty || 0),
          line_po_id: grItem.line_po_id,
          line_gr_id: grItem.goods_receiving_id,
          item_category_id: grItem.item_category_id,
          tariff_id: grItem.tariff_id
        };

        tablePI.push(newTablePIRecord);
      }
      break;
  }

  tablePI = tablePI.filter(
    (pi) =>
      pi.invoice_qty !== 0 &&
      !existingPI.find((piItem) => piItem.po_line_id === pi.po_line_id),
  );

  const latestTablePI = [...existingPI, ...tablePI];

  poId = [...new Set(latestTablePI.map((pi) => pi.line_po_id))];
  purchaseOrderNumber = [
    ...new Set(latestTablePI.map((pi) => pi.purchase_order_no)),
  ];

  grId = [...new Set(latestTablePI.map((pi) => pi.line_gr_id))];
  goodsReceivingNumber = [
    ...new Set(latestTablePI.map((pi) => pi.goods_receiving_no)),
  ];

  console.log("tablePI", tablePI);
  await this.setData({
    supplier_name: referenceType.startsWith("Document")
      ? currentItemArray[0].supplier_id
      : currentItemArray[0].supplier.id,
    table_pi: [...existingPI, ...tablePI],
    po_no_display: purchaseOrderNumber.join(", "),
    po_id: poId,
    gr_no_display: goodsReceivingNumber.join(", "),
    gr_id: grId,
    reference_type: referenceType,
  });

  setTimeout(async () => {
    await processData(tablePI, referenceType);
  }, 50);

  this.triggerEvent("PIcalculation", { PIlineItem: tablePI });
  this.triggerEvent("onChange_supplier");

  this.hideLoading();
})();

const data = this.getValues();
const supplierId = data.supplier_name;
if (!supplierId) {
  return;
}

// Address
if (supplierId.length > 0) {
  this.display("address_grid");
  const resetFormFields = () => {
    this.setData({
      pi_billing_name: "",
      pi_billing_cp: "",
      pi_shipping_address: "",
      pi_billing_address: "",
      billing_address_line_1: "",
      billing_address_line_1: "",
      billing_address_line_2: "",
      billing_address_line_3: "",
      billing_address_line_4: "",
      billing_address_city: "",
      billing_address_state: "",
      billing_postal_code: "",
      billing_address_country: "",
      billing_address_name: '',
      billing_attention: '',
      billing_address_fax: '',
      shipping_address_line_1: "",
      shipping_address_line_2: "",
      shipping_address_line_3: "",
      shipping_address_line_4: "",
      shipping_address_city: "",
      shipping_address_state: "",
      shipping_postal_code: "",
      shipping_address_country: "",
      shipping_address_name: '',
      shipping_attention: '',
      shipping_address_fax: '',
    });
  };

  resetFormFields();

  Promise.all([
    db.collection("address_purpose").where({ purpose_name: "Shipping" }).get(),
    db.collection("supplier_head").where({ id: supplierId }).get(),
  ]).then(async ([resShipping, resSupplier]) => {
    if (resSupplier.data.length === 0 || resShipping.data.length === 0) return;

    const supplierData = resSupplier.data[0];
    const shippingAddrId = resShipping.data[0].id;

    const addresses = supplierData.address_list.filter(
      (address) => address.switch_save_as_default
    );

    if (addresses.length > 0) {
      addresses.forEach(async (address) => {
        let country = "";
        let state = "";
        if (address.address_country_id) {
          const resCountry = await db
            .collection("country")
            .where({ id: address.address_country_id })
            .get();
          country = resCountry?.data[0]?.country_name || "";
        }

        if (address.adddress_state) {
          const resState = await db
            .collection("state")
            .where({ id: address.adddress_state })
            .get();
          state = resState?.data[0]?.state_name || "";
        }

        const isShipping = address.address_purpose_id === shippingAddrId;
        const addressType = isShipping ? "shipping" : "billing";
        const addressTypeUpperCase = isShipping ? "Shipping" : "Billing";

        const addressLines = [
          address.address_line_1,
          address.address_line_2,
          address.address_line_3,
          address.address_line_4,
        ]
          .filter((line) => line)
          .join(
            (
              [
                address.address_line_1,
                address.address_line_2,
                address.address_line_3,
                address.address_line_4,
              ]
                .filter((line) => line)
                .pop() || ""
            ).endsWith(",")
              ? " "
              : ", "
          );

        const cityDetails = [
          address.address_city,
          address.address_postal_code,
          address.adddress_state ? state : "",
          address.address_country_id ? country : "",
        ]
          .filter((detail) => detail)
          .join(
            (
              [
                address.address_city,
                address.address_postal_code,
                address.adddress_state ? state : "",
                address.address_country_id ? country : "",
              ]
                .filter((detail) => detail)
                .pop() || ""
            ).endsWith(",")
              ? " "
              : ", "
          );

        const addressAttention = address.address_attention
          ? "\nAttention: " + address.address_attention
          : "";

        const addressPurposeName = `\n${addressTypeUpperCase}` + " Address";

        const addressPersonParts = [
          address.address_name,
          address.address_phone,
        ].filter((part) => part); // Remove undefined or null
        const addressPerson =
          addressPersonParts.length > 0 ? addressPersonParts.join(" | ") : "";

        const formattedAddress = [
          addressPerson,
          addressPurposeName,
          addressLines,
          cityDetails,
          addressAttention,
        ]
          .filter(Boolean)
          .join("\n");

        this.setData({
          [`${addressType}_address_line_1`]: address.address_line_1,
          [`${addressType}_address_line_2`]: address.address_line_2,
          [`${addressType}_address_line_3`]: address.address_line_3,
          [`${addressType}_address_line_4`]: address.address_line_4,
          [`${addressType}_address_city`]: address.address_city,
          [`${addressType}_address_state`]: address.adddress_state,
          [`${addressType}_postal_code`]: address.address_postal_code,
          [`${addressType}_address_country`]: address.address_country_id,
          [`${addressType}_address_name`]: address.address_name,
          [`${addressType}_address_phone`]: address.address_phone,
          [`${addressType}_attention`]: address.address_attention,
          [`pi_${addressType}_address`]: formattedAddress,
        });
      });
    }
  });
}

this.setData({
  [`dialog_select_item.reference_type`]: '',
  [`dialog_select_item.item_array`]: [],
  [`dialog_select_item.doc_number_array`]: '',
})

(async () => {
  setTimeout(() => {
    (async () => {
      const tablePI = await this.getValue("table_pi");
      console.log("tablePI", tablePI);

      let poId = tablePI.map((pi) => pi.line_po_id);
      let purchaseOrderNumber = tablePI.map((pi) => pi.purchase_order_no);
      let grId = tablePI.map((pi) => pi.line_gr_id);
      let goodsReceivingNumber = tablePI.map((pi) => pi.goods_receiving_no);

      poId = [...new Set(poId)];
      purchaseOrderNumber = [...new Set(purchaseOrderNumber)];
      grId = [...new Set(grId)];
      goodsReceivingNumber = [...new Set(goodsReceivingNumber)];

      console.log(poId, purchaseOrderNumber);
      await this.setData({
        po_id: poId,
        po_no_display: purchaseOrderNumber.join(", "),
        gr_id: grId,
        gr_no_display: goodsReceivingNumber.join(", "),
      });

      await this.triggerEvent("PIcalculation");
    })();
  }, 50);
})();

